const PROFANITY_REGEX = /\b(conchetumare|ctm|culiao|qliao|pichula|tula|zorra|maraco|maricón|maricon|puta|mierda|fuck|shit|asshole|bitch|bastard|motherfucker|dick|cunt|pussy|prick|estúpido|estupido|idiota|imbécil|imbecil|gilipollas|huevon|weon)\b/i;

const INJECTION_PHRASES = [
  'ignore all previous instructions', 'disregard all rules', 'system prompt',
