  throw { success: false, error_code: 'JSON_INVALID', error_message: 'El JSON extraído es inválido.' };
}

params.chat_id = $('Input_Clean').first().json.chat_id || 0;

const bookingId = String(params.booking_id || '').trim();
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const shortCodeRegex = /^BKG-[A-Z0-9]{6,10}$/i;

if (!uuidRegex.test(bookingId) && !shortCodeRegex.test(bookingId)) {
  // HARD FALLBACK: buscar código corto en el texto original si el LLM no lo puso en el JSON
  const userText = $('Input_Clean').first().json.text;
  const match = userText.match(/BKG-[A-Z0-9]{6,10}/i);
  if (match) {
    params.booking_id = match[0].toUpperCase();
  } else {
    throw {
      success: false,
      error_code: 'INVALID_BOOKING_ID',
      error_message: 'No se encontró un código de reserva válido (ej: BKG-123456).'
    };
  }
} else {
  params.booking_id = bookingId.toUpperCase();
}

return [{ json: params }];

