} catch(e) { params = {}; }

const userText = $('Input_Clean').first().json.text;
const userTextLower = userText.toLowerCase();
let q = params.query || ""; // Confiar en el LLM primero

// #5 ✅ CORRECTO --- LLM tiene prioridad, keywords son fallback
if (!q) {
  const kws = [
    { test: ["cardio","corazón","arritmia"], val: "cardiologia" },
    { test: ["pediat","niño","niña","infantil"], val: "pediatria" },
    { test: ["derma","piel","acné"], val: "dermatologia" },
    { test: ["odont","diente","dental","muela"], val: "odontologia" },
    { test: ["segu","osde","prepaga","cobertura"], val: "seguros" },
  ];

  for (const { test, val } of kws) {
    if (test.some(k => userTextLower.includes(k))) { 
      q = val; 
      break; 
    }
  }
}

// Último recurso: texto completo del usuario
if (!q || q.length < 2 || q.includes('normaliz') || q === 'unknown') {
  q = userText;
}

return [{ json: {
  query: q.toLowerCase().trim(),
  service_name: q.toLowerCase().trim(),
  provider_id: 1,
  limit: 5,
  similarity_threshold: 0.30 // #4 ✅ 30% --- balance recall/precision
} }];

// Analyze Resolve — Decidir estrategia RAG (SEC02)
const resolve = $input.first()?.json.data || {};
const userText = $('Input_Clean').first().json.text;
const parseData = $('Parse: get_services').first()?.json || {};

// Si el match es débil o no encontrado, buscar en RAG sin filtro de service_id
const useFilter = resolve.resolved && resolve.match_type !== 'WEAK';

return [{
  json: {
    query: resolve.resolved ? resolve.service_name : (parseData.query || userText),
    provider_id: resolve.provider_id || 1,
    service_id: useFilter ? resolve.service_id : null,
    limit: 5,
    similarity_threshold: 0.05,
    sql_context: {
      resolved: resolve.resolved,
      match_type: resolve.match_type,
      service_name: resolve.service_name,
      price: resolve.price,
      currency: resolve.currency || 'USD',
      candidates: resolve.candidates || []
    }
  }
}];

